# ── Version & Auto-update ────────────────────────────────────────────────────
VERSION = "1.2.0"
UPDATE_URL = "https://raw.githubusercontent.com/manisokham-cloud/maymay/main/maymay.py"

def check_update():
    """Vérifie si une nouvelle version est disponible et propose la mise à jour."""
    try:
        import urllib.request, re, os, threading
        def _check():
            try:
                req = urllib.request.urlopen(UPDATE_URL, timeout=3)
                remote = req.read().decode('utf-8', errors='ignore')
                m = re.search(r'VERSION\s*=\s*"([\d.]+)"', remote)
                if not m:
                    return
                remote_ver = tuple(int(x) for x in m.group(1).split('.'))
                local_ver  = tuple(int(x) for x in VERSION.split('.'))
                if remote_ver > local_ver:
                    print(f"[MAYMAY] Nouvelle version {m.group(1)} disponible !")
                    # Sauvegarde l'ancien fichier
                    script = os.path.abspath(__file__)
                    backup = script + ".bak"
                    os.replace(script, backup)
                    with open(script, 'w', encoding='utf-8') as f:
                        f.write(remote)
                    print(f"[MAYMAY] Mise à jour installée ! Relance le jeu.")
                    # Signal pour afficher le popup dans le jeu
                    global UPDATE_DONE
                    UPDATE_DONE = True
                else:
                    print(f"[MAYMAY] Version {VERSION} - à jour ✓")
            except Exception as e:
                print(f"[MAYMAY] Vérification update impossible: {e}")
        t = threading.Thread(target=_check, daemon=True)
        t.start()
    except Exception:
        pass

UPDATE_DONE = False
check_update()

